sp_widget.client_script:
function ($scope, $rootScope, spUtil) {
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: FIELDS
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
//------------------------------------------------------------------------------------------------------------------------
	//spUtil.recordWatch($scope, $scope.data.table, "sys_id=" + $scope.data.sys_id); 
	var c = this;

	var onSaveUpdate = $scope.$on('sp.form.record.updated', refreshWidget);



	$rootScope.$on('$TaskerTaskList.click', function(e, parms) {
		c.data.table = parms.table;
		c.data.sys_id = parms.sys_id;
		refreshWidget();
	});
	$rootScope.$on('$sp.list.click', function(e, parms) {
		c.data.sys_id = parms.sys_id;
		c.data.table = parms.table;
		refreshWidget();
	});
	$rootScope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
		c.data.sys_id = parms.sys_id;
		c.data.table = parms.table;
		refreshWidget();
	});



	function refreshWidget(evt,arg) {
		$scope.server.update();
	}
}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// NAME: Tasker States Progress Bar
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// WIDGET BASE: FIELDS
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 08.31.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------

.progress {
	height: 48px;
}

.progress-bar {
  font-size: 14px!important;
  vertical-align: middle;
  text-align: center;
  padding-top: 5px;
}

//------------------------------------------------------------------------------------------------------------------------
// STATES
//------------------------------------------------------------------------------------------------------------------------

.bg-waiting {
  	background-color: $state-waiting-bg;
		color: $state-waiting-text;
}

.bg-unassigned {
  	background-color: $state-unassigned-bg;
  	color: $state-unassigned-text;  
}

.bg-assigned {
  	background-color: $state-assigned-bg;
		color: $state-assigned-text;
}

.bg-accepted {
  	background-color: $state-accepted-bg;
		color: $state-accepted-text;
}

.bg-rejected {
  	background-color: $state-rejected-bg;
		color: $state-rejected-text;
}

.bg-workscheduled {
  	background-color: $state-workscheduled-bg;
		color: $state-workscheduled-text;
}

.bg-workinprogress {
  	background-color: $state-workinprogress-bg;
		color: $state-workinprogress-text;
}

.bg-inreview {
  	background-color: $state-inreview-bg; 
		color: $state-inreview-text;
}

.bg-rework {
  	background-color: $state-rework-bg;
		color: $state-rework-text;
}

.bg-completed {
  	background-color: $state-completed-bg;
		color: $state-completed-text;
}

.bg-closedincomplete {
  	background-color: $state-closedincomplete-bg;
		color: $state-closedincomplete-text;
}

.bg-cancelled {
  	background-color: $state-cancelled-bg;
		color: $state-cancelled-text;
}

sp_widget.script:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// WIDGET BASE: FIELDS
//------------------------------------------------------------------------------------------------------------------------
(function(data){
	data.pickupMsg = gs.getMessage(options.pickup_msg);
	data.page = $sp.getParameter("id");

	var gr;

	if(input){
		data.table = input.table;
		data.sys_id = input.sys_id;
		gr = new GlideRecordSecure(data.table);
		if(!gr.get(data.sys_id)){
			return;
		}
	} else {
		gr = $sp.getRecord();
		if (gr == null)
			return;

	}


	data.canRead = gr.canRead();
	if (!data.canRead)
		return;

	data.tableLabel = gr.getLabel();
	data.table = gr.getTableName();
	data.sys_id = gr.getUniqueValue();
	data.dynamic_tree = $sp.getParameter("dynamic_tree"); // KT - TLV - STRY0057360 - Macro Widget
	data.page = $sp.getParameter("id");
	//------------------------------------------------------ KTorres
	data.nWaiting = 0;
	data.nUnassigned = 0;
	data.nAssigned = 0;
	data.nAccepted = 0;
	data.nRejected = 0;
	data.nWorkScheduled = 0;
	data.nInProgress = 0;
	data.nInReview = 0;
	data.nRework =0;
	data.nCompleted = 0;
	data.nCancelled = 0;
	data.nIncompleted = 0;

	/*
	-5	Awaiting Assignment
	1	Awaiting Acceptance
	10	Assignment Accepted
	11	Assignment Rejected
	12	Work Scheduled
	13	Work in Progress
	14	In Review
	15	Rework
	3	Closed Complete
	4	Closed Incomplete
	7	Closed Skipped
	*/


	data.calchaschildren = gr.getValue('calchaschildren');

	if(data.calchaschildren > 0){
		data.nWaiting = getStateCount(data.table, data.sys_id, -3, data.dynamic_tree);
		data.nUnassigned = getStateCount(data.table, data.sys_id, -5, data.dynamic_tree);
		data.nAssigned = getStateCount(data.table, data.sys_id, 1, data.dynamic_tree);
		data.nAccepted = getStateCount(data.table, data.sys_id, 10, data.dynamic_tree);
		data.nRejected = getStateCount(data.table, data.sys_id, 11, data.dynamic_tree);
		data.nWorkScheduled = getStateCount(data.table, data.sys_id, 12, data.dynamic_tree);
		data.nInProgress = getStateCount(data.table, data.sys_id, 13, data.dynamic_tree);
		data.nInReview = getStateCount(data.table, data.sys_id, 14, data.dynamic_tree);
		data.nRework = getStateCount(data.table, data.sys_id, 15, data.dynamic_tree);
		data.nCompleted = getStateCount(data.table, data.sys_id, 3, data.dynamic_tree);
		data.nIncompleted = getStateCount(data.table, data.sys_id, 4, data.dynamic_tree);
		data.nCanceled = getStateCount(data.table, data.sys_id, 7, data.dynamic_tree);
	}

	//-------------------------------------------------------------------------------------------------------------------
	function getStateCount(table, sys_id, statevalue, dynamic_tree) {

		var nTotal = 0;
		var nSubTotal = 0;
		var grTaskInstance;
		var grTaskInstanceSubTotal;
		var percentage = 0;
		var filter = 'u_all_ancestors_tasksLIKE'+ sys_id;

		grTaskInstance = new GlideAggregate(table);
		if (data.dynamic_tree == 'true') grTaskInstance.addQuery('u_all_ancestors_tasks', 'CONTAINS', sys_id); else grTaskInstance.addQuery('parent',sys_id); // KT - TLV - STRY0057360 - Macro Widget
		grTaskInstance.addAggregate('COUNT');
		grTaskInstance.query();

		if(grTaskInstance.next()) {
			nTotal = grTaskInstance.getAggregate('COUNT');
		}

		grTaskInstanceSubTotal = new GlideAggregate(table);
		if (data.dynamic_tree == 'true') grTaskInstanceSubTotal.addQuery('u_all_ancestors_tasks', 'CONTAINS', sys_id); else grTaskInstanceSubTotal.addQuery('parent',sys_id); // KT - TLV - STRY0057360 - Macro Widget
		grTaskInstanceSubTotal.addQuery('state',statevalue);
		grTaskInstanceSubTotal.addAggregate('COUNT');
		grTaskInstanceSubTotal.query();


		if(grTaskInstanceSubTotal.next()) {
			nSubTotal = grTaskInstanceSubTotal.getAggregate('COUNT');
			percentage = (nSubTotal * 100 / nTotal).toFixed(3); //<!-- // KT - TLV - STRY0057360 - Macro Widget: Updated to 2 -->
		}
		return percentage;
	}

})(data)
